@functions_framework.http
def payment_webhook(request):
    """
    HTTP Cloud Function endpoint for processing payment webhook events.

    Deploy with:
        gcloud functions deploy payment-webhook \
            --gen2 \
            --runtime python312 \
            --trigger-http \
            --allow-unauthenticated \
            --entry-point payment_webhook \
            --set-env-vars WEBHOOK_SECRET=your-shared-secret \
            --region us-central1

    Expected request format:
        POST with JSON body:
        {
            "event_type": "payment.completed",
            "event_id": "evt_unique_123",
            "timestamp": "2024-01-15T10:30:00Z",
            "data": {
                "payment_id": "pay_abc123",
                "amount": 99.99,
                "currency": "USD",
                "customer_id": "cust_xyz",
                ...
            }
        }

    Headers:
        Content-Type: application/json
        X-Webhook-Signature: sha256=<hmac_hex_digest>
        X-Partner-ID: <partner_identifier> (optional)
    """

    # --- Method Check ---
    if request.method == "OPTIONS":
        # Handle CORS preflight
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "POST",
            "Access-Control-Allow-Headers": "Content-Type, X-Webhook-Signature, X-Partner-ID",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    if request.method != "POST":
        logger.warning(f"Rejected non-POST request: {request.method}")
        return (
            json.dumps({"error": "Method not allowed. Use POST."}),
            405,
            {"Content-Type": "application/json"},
        )

    # --- IP Verification (optional) ---
    if not verify_ip(request):
        return (
            json.dumps({"error": "Forbidden"}),
            403,
            {"Content-Type": "application/json"},
        )

    # --- Get raw body for signature verification ---
    raw_body = request.get_data()

    if not raw_body:
        logger.warning("Empty request body received")
        return (
            json.dumps({"error": "Empty request body"}),
            400,
            {"Content-Type": "application/json"},
        )

    # --- Signature Verification ---
    signature = request.headers.get("X-Webhook-Signature", "")

    if WEBHOOK_SECRET:
        if not verify_signature(raw_body, signature, WEBHOOK_SECRET):
            logger.warning("Invalid webhook signature")
            return (
                json.dumps({"error": "Invalid signature"}),
                401,
                {"Content-Type": "application/json"},
            )
        logger.info("Webhook signature verified successfully")
    else:
        logger.warning(
            "WEBHOOK_SECRET not configured - signature verification skipped. "
            "This is insecure for production use!"
        )

    # --- Parse JSON Body ---
    try:
        payload = request.get_json(force=True)
    except Exception as e:
        logger.error(f"Failed to parse JSON body: {e}")
        return (
            json.dumps({"error": "Invalid JSON payload"}),
            400,
            {"Content-Type": "application/json"},
        )

    if not isinstance(payload, dict):
        return (
            json.dumps({"error": "Payload must be a JSON object"}),
            400,
            {"Content-Type": "application/json"},
        )

    # --- Validate Payload ---
    is_valid, validation_error = validate_payload(payload)
    if not is_valid:
        logger.warning(f"Payload validation failed: {validation_error}")
        return (
            json.dumps({"error": f"Validation error: {validation_error}"}),
            422,
            {"Content-Type": "application/json"},
        )

    event_type = payload["event_type"]
    event_id = payload["event_id"]
    event_data = payload["data"]
    partner_id = request.headers.get("X-Partner-ID", "unknown")

    logger.info(
        f"Received webhook: event_type={event_type}, event_id={event_id}, "
        f"partner={partner_id}"
    )

    # --- Idempotency Check ---
    if check_idempotency(event_id):
        logger.info(f"Duplicate event detected, skipping: {event_id}")
        return (
            json.dumps({
                "status": "already_processed",
                "event_id": event_id,
                "message": "This event has already been processed.",
            }),
            200,
            {"Content-Type": "application/json"},
        )

    # --- Process Event ---
    try:
        handler = EVENT_HANDLERS.get(event_type)
        if handler:
            result = handler(event_id, event_data)
        else:
            result = process_generic_event(event_type, event_id, event_data)

        # Store event for idempotency and audit
        store_event(event_id, {
            "event_type": event_type,
            "event_id": event_id,
            "partner_id": partner_id,
            "payload": payload,
            "result": result,
            "processed_at": datetime.now(timezone.utc).isoformat(),
        })

        logger.info(f"Successfully processed event: {event_id}")

        return (
            json.dumps({
                "status": "success",
                "event_id": event_id,
                "result": result,
            }),
            200,
            {"Content-Type": "application/json"},
        )

    except Exception as e:
        logger.error(f"Error processing event {event_id}: {e}", exc_info=True)

        # Return 500 so the partner knows to retry
        return (
            json.dumps({
                "status": "error",
                "event_id": event_id,
                "message": "Internal processing error. Please retry later.",
            }),
            500,
            {"Content-Type": "application/json"},
        )